const cutoff = Date.now() - 7 * 24 * 60 * 60 * 1000;
const items = $input.all();
const out = [];

for (const item of items) {
  const feedName = item.json.feed_url
    ? item.json.feed_url
    : '';
  // The HTTP node returns the body as 'data' or as the raw response
  const xml = (typeof item.json.data === 'string') ? item.json.data : (item.json.body || '');

  // Parse <item> blocks via regex (no DOM parser in n8n sandbox)
  const itemBlocks = xml.match(/<item[\s>][\s\S]*?<\/item>/gi) || [];
  let count = 0;

  // Try to extract feed name from channel title
  const chanTitleMatch = xml.match(/<channel>[\s\S]*?<title><!\[CDATA\[(.*?)\]\]><\/title>/i)
    || xml.match(/<channel>[\s\S]*?<title>(.*?)<\/title>/i);
  // Get feed_url and name from the pairing — we stored in the item's upstream context
  // We need to find which feed this is. We'll use pairing index fallback.

  for (const block of itemBlocks) {
    if (count >= 5) break;

    const titleMatch = block.match(/<title><!\[CDATA\[([\s\S]*?)\]\]><\/title>/)
      || block.match(/<title>([\s\S]*?)<\/title>/);
    const linkMatch = block.match(/<link>([\s\S]*?)<\/link>/)
      || block.match(/<guid[^>]*>(https?:\/\/[^<]+)<\/guid>/);
    const pubDateMatch = block.match(/<pubDate>([\s\S]*?)<\/pubDate>/)
      || block.match(/<published>([\s\S]*?)<\/published>/);
    const descMatch = block.match(/<description><!\[CDATA\[([\s\S]*?)\]\]><\/description>/)
      || block.match(/<description>([\s\S]*?)<\/description>/);
    const contentMatch = block.match(/<content:encoded><!\[CDATA\[([\s\S]*?)\]\]><\/content:encoded>/)
      || block.match(/<content:encoded>([\s\S]*?)<\/content:encoded>/);

    const title = titleMatch ? titleMatch[1].trim() : '';
    const url = linkMatch ? linkMatch[1].trim().replace(/<!\[CDATA\[/, '').replace(/\]\]>/, '') : '';
    const pubDate = pubDateMatch ? pubDateMatch[1].trim() : '';
    const desc = descMatch ? descMatch[1].replace(/<[^>]+>/g, '').trim() : '';
    const content = contentMatch ? contentMatch[1].replace(/<[^>]+>/g, '').trim() : desc;

    if (!title || !url) continue;

    // Date filter
    const ts = pubDate ? Date.parse(pubDate) : 0;
    if (ts && ts < cutoff) continue;

    out.push({ json: {
      title: title.substring(0, 500),
      url: url.substring(0, 2000),
      published_at: pubDate ? new Date(pubDate).toISOString().substring(0, 10) : '',
      description: desc.substring(0, 500),
      feed_name: item.json.feed_name || '',
    }});
    count++;
  }
}

return out.length ? out : [{ json: { _empty: true } }];

const articles = $('Parse RSS Items').all().map(it => it.json).filter(a => !a._empty);
const existing = $input.all();
const existingUrls = new Set();
for (const e of existing) {
  const results = (e.json.results) || [];
  for (const page of results) {
    const ep = (page.properties && page.properties.Episode && page.properties.Episode.rich_text) || [];
    for (const seg of ep) {
      const u = (seg.text && seg.text.link && seg.text.link.url) || '';
      if (u) existingUrls.add(u);
    }
  }
}
const newOnes = articles.filter(a => !existingUrls.has(a.url));
return newOnes.length ? newOnes.map(a => ({ json: a })) : [{ json: { _empty: true } }];

const TOPIC_ALIASES = {
  "google gemini": "Google", "gemini": "Google", "google": "Google",
  "chatgpt": "OpenAI", "gpt-5": "OpenAI", "gpt-4": "OpenAI", "openai": "OpenAI",
  "anthropic": "Anthropic", "claude": "Claude",
  "meta ai": "Meta", "llama": "Meta", "meta": "Meta",
  "agent": "Agents", "agents": "Agents", "agentic": "Agents", "agentic ai": "Agents",
  "governance": "AI Governance", "ai governance": "AI Governance", "responsible ai": "AI Governance", "ethics": "AI Governance",
  "safety": "AI Safety", "ai safety": "AI Safety", "alignment": "AI Safety",
  "policy": "Policy", "regulation": "Policy", "eu ai act": "Policy",
  "marketing": "Marketing AI", "marketing ai": "Marketing AI", "advertising": "Marketing AI", "adtech": "Marketing AI",
  "measurement": "Measurement", "attribution": "Measurement",
  "strategy": "AI Strategy", "ai strategy": "AI Strategy",
  "llm": "LLMs", "llms": "LLMs", "large language model": "LLMs",
  "mcp": "MCP", "model context protocol": "MCP",
  "voice": "Voice AI", "voice ai": "Voice AI",
  "enterprise": "Enterprise AI", "enterprise ai": "Enterprise AI",
  "creator": "Creator Economy", "creator economy": "Creator Economy",
  "research": "Research", "paper": "Research",
  "content": "Content",
  "prompt": "Prompt Engineering", "prompt engineering": "Prompt Engineering",
  "search": "Reddit/Search",
  "codex": "Codex",
};
const VALID_TOPICS = new Set(["Claude","Agents","AI Governance","Marketing AI","Measurement","AI Strategy","LLMs","MCP","Voice AI","AI Safety","Enterprise AI","Creator Economy","Policy","Research","Content","Prompt Engineering","Reddit/Search","OpenAI","Anthropic","Google","Meta","Codex"]);
function normalize(topic) {
  const k = String(topic || '').trim().toLowerCase();
  if (TOPIC_ALIASES[k]) return TOPIC_ALIASES[k];
  for (const [alias, target] of Object.entries(TOPIC_ALIASES)) {
    if (k.includes(alias)) return target;
  }
  return null;
}
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  let text = '';
  if (j.content && Array.isArray(j.content) && j.content[0]) text = j.content[0].text || '';
  else if (typeof j.body === 'string') text = j.body;
  else text = JSON.stringify(j);
  text = text.replace(/^```json\s*/i,'').replace(/```\s*$/,'').trim();
  let parsed;
  try { parsed = JSON.parse(text); } catch(e) { continue; }
  const ideas = parsed.ideas || [];
  const ctx = $('Carry Article Context').item.json;
  for (const idea of ideas) {
    const merged = new Set();
    for (const t of (idea.topics || [])) {
      const n = normalize(t);
      if (n && VALID_TOPICS.has(n)) merged.add(n);
    }
    if (!merged.size) merged.add('AI Strategy');
    if (String(idea.relevance||'').toLowerCase()==='low' && String(idea.utility||'').toLowerCase()==='low') continue;
    out.push({ json: {
      topic_headline: idea.topic_headline || '',
      hook: idea.hook || '',
      key_points: idea.key_points || [],
      observations: idea.observations || [],
      tips: idea.tips || [],
      quotes: idea.quotes || [],
      audience: idea.audience || [],
      hot_take_potential: idea.hot_take_potential || 'Medium',
      utility: idea.utility || 'Medium',
      relevance: idea.relevance || 'Medium',
      format: idea.format || 'Explainer',
      draft_angle: idea.draft_angle || '',
      why_it_matters: idea.why_it_matters || '',
      further_reading: idea.further_reading || [],
      merged_topics: Array.from(merged),
      feed_name: ctx.article_feed || '',
      article_title: ctx.article_title || '',
      article_url: ctx.article_url || '',
      article_published: ctx.article_published || '',
      source_type: 'web',
      extraction_model: 'Sonnet 4.6',
    }});
  }
}
return out.length ? out : [{ json: { _no_ideas: true } }];

